create table pis_storitve_pos.napaka_odgovora (
    id           number(19, 0) not null enable,
    version      number(19, 0) default 0 not null enable,
    odgovor_id   number(19, 0) not null enable,
    source       varchar2(20 char) not null enable,
    error_code   varchar2(100 char) not null enable,
    opis         varchar2(2000 char) not null enable,
    datum_napake timestamp(6) not null enable,
    status       varchar2(30 char) not null enable,
    datum_cre    timestamp(6) not null enable,
    datum_mod    timestamp(6),
    ident        varchar2(100 char)
);

alter table pis_storitve_pos.napaka_odgovora
    add constraint pk_napaka primary key ( id )
        using index enable;


